1	import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
2	import { renderHook, act } from "@testing-library/react";
3	import { AssumptionProvider, useAssumptions } from "@/features/assumptions/AssumptionContext";
4	import type { ReactNode } from "react";
5	
6	function wrapper({ children }: { children: ReactNode }) {
7	  return <AssumptionProvider>{children}</AssumptionProvider>;
8	}
9	
10	describe("AssumptionContext", () => {
11	  describe("initial state", () => {
12	    it("starts with empty assumptions array", () => {
13	      const { result } = renderHook(() => useAssumptions(), { wrapper });
14	      expect(result.current.assumptions).toEqual([]);
15	    });
16	
17	    it("hasAssumption returns false for any variableId", () => {
18	      const { result } = renderHook(() => useAssumptions(), { wrapper });
19	      expect(result.current.hasAssumption("v1")).toBe(false);
20	    });
21	
22	    it("getAssumption returns undefined for any variableId", () => {
23	      const { result } = renderHook(() => useAssumptions(), { wrapper });
24	      expect(result.current.getAssumption("v1")).toBeUndefined();
25	    });
26	
27	    it("contextPayload is empty array", () => {
28	      const { result } = renderHook(() => useAssumptions(), { wrapper });
29	      expect(result.current.contextPayload).toEqual([]);
30	    });
31	  });
32	
33	  describe("addAssumption", () => {
34	    it("adds a single assumption", () => {
35	      const { result } = renderHook(() => useAssumptions(), { wrapper });
36	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "Label 1" }));
37	      expect(result.current.assumptions).toEqual([
38	        { variableId: "v1", outcomeId: "o1", label: "Label 1" },
39	      ]);
40	    });
41	
42	    it("adds multiple assumptions with different variableIds", () => {
43	      const { result } = renderHook(() => useAssumptions(), { wrapper });
44	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
45	      act(() => result.current.addAssumption({ variableId: "v2", outcomeId: "o2", label: "L2" }));
46	      expect(result.current.assumptions).toHaveLength(2);
47	      expect(result.current.assumptions[0]!.variableId).toBe("v1");
48	      expect(result.current.assumptions[1]!.variableId).toBe("v2");
49	    });
50	
51	    it("replaces assumption with same variableId", () => {
52	      const { result } = renderHook(() => useAssumptions(), { wrapper });
53	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "Old" }));
54	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o2", label: "New" }));
55	      expect(result.current.assumptions).toHaveLength(1);
56	      expect(result.current.assumptions[0]).toEqual({ variableId: "v1", outcomeId: "o2", label: "New" });
57	    });
58	  });
59	
60	  describe("removeAssumption", () => {
61	    it("removes an existing assumption by variableId", () => {
62	      const { result } = renderHook(() => useAssumptions(), { wrapper });
63	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
64	      act(() => result.current.removeAssumption("v1"));
65	      expect(result.current.assumptions).toEqual([]);
66	    });
67	
68	    it("is a no-op when removing non-existent variableId", () => {
69	      const { result } = renderHook(() => useAssumptions(), { wrapper });
70	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
71	      act(() => result.current.removeAssumption("v-nonexistent"));
72	      expect(result.current.assumptions).toHaveLength(1);
73	    });
74	  });
75	
76	  describe("clearAll", () => {
77	    it("removes all assumptions", () => {
78	      const { result } = renderHook(() => useAssumptions(), { wrapper });
79	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
80	      act(() => result.current.addAssumption({ variableId: "v2", outcomeId: "o2", label: "L2" }));
81	      act(() => result.current.clearAll());
82	      expect(result.current.assumptions).toEqual([]);
83	    });
84	  });
85	
86	  describe("hasAssumption and getAssumption", () => {
87	    it("hasAssumption returns true for existing variableId", () => {
88	      const { result } = renderHook(() => useAssumptions(), { wrapper });
89	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
90	      expect(result.current.hasAssumption("v1")).toBe(true);
91	    });
92	
93	    it("hasAssumption returns false for missing variableId", () => {
94	      const { result } = renderHook(() => useAssumptions(), { wrapper });
95	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
96	      expect(result.current.hasAssumption("v2")).toBe(false);
97	    });
98	
99	    it("getAssumption returns the matching Assumption", () => {
100	      const { result } = renderHook(() => useAssumptions(), { wrapper });
101	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
102	      expect(result.current.getAssumption("v1")).toEqual({ variableId: "v1", outcomeId: "o1", label: "L1" });
103	    });
104	
105	    it("getAssumption returns undefined for missing variableId", () => {
106	      const { result } = renderHook(() => useAssumptions(), { wrapper });
107	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
108	      expect(result.current.getAssumption("v2")).toBeUndefined();
109	    });
110	  });
111	
112	  describe("contextPayload", () => {
113	    it("contains only variableId and outcomeId (no label)", () => {
114	      const { result } = renderHook(() => useAssumptions(), { wrapper });
115	      act(() => result.current.addAssumption({ variableId: "v1", outcomeId: "o1", label: "L1" }));
116	      act(() => result.current.addAssumption({ variableId: "v2", outcomeId: "o2", label: "L2" }));
117	      expect(result.current.contextPayload).toEqual([
118	        { variableId: "v1", outcomeId: "o1" },
119	        { variableId: "v2", outcomeId: "o2" },
120	      ]);
121	    });
122	  });
123	
124	  describe("useAssumptions outside provider", () => {
125	    const originalError = console.error;
126	    beforeEach(() => { console.error = vi.fn(); });
127	    afterEach(() => { console.error = originalError; });
128	
129	    it("throws when used outside AssumptionProvider", () => {
130	      expect(() => renderHook(() => useAssumptions())).toThrow(
131	        "useAssumptions must be used within AssumptionProvider",
132	      );
133	    });
134	  });
135	});
