28	      );
29	      const { result } = renderHook(() => useSession(), { wrapper });
30	      expect(result.current.session).toEqual({ accountId: "acc-1", agentId: "agent-1" });
31	    });
32	
33	    it("returns defaults for invalid JSON (corrupt storage)", () => {
34	      localStorage.setItem(STORAGE_KEY, "not-json{{{");
35	      const { result } = renderHook(() => useSession(), { wrapper });
36	      expect(result.current.session).toEqual({ accountId: "", agentId: "" });
