73	    });
74	  });
75	
76	  describe("isConfigured", () => {
77	    it("is false when both accountId and agentId are empty", () => {
78	      const { result } = renderHook(() => useSession(), { wrapper });
79	      expect(result.current.isConfigured).toBe(false);
80	    });
81	
82	    it("is true when accountId is set and agentId is empty", () => {
83	      localStorage.setItem(
84	        STORAGE_KEY,
85	        JSON.stringify({ accountId: "acc-1", agentId: "" }),
