1	import { createContext, useContext, useReducer, useCallback, type ReactNode } from "react";
2	import type { Command } from "./commands";
3	
4	export const HISTORY_CAP = 50;
5	
6	interface HistoryState {
7	  undoStack: Command[];
8	  redoStack: Command[];
9	}
10	
11	type HistoryAction =
12	  | { type: "PUSH"; command: Command }
13	  | { type: "UNDO" }
14	  | { type: "REDO" }
15	  | { type: "CLEAR" };
16	
17	function historyReducer(state: HistoryState, action: HistoryAction): HistoryState {
18	  switch (action.type) {
19	    case "PUSH": {
20	      const undoStack = [...state.undoStack, action.command].slice(-HISTORY_CAP);
21	      return { undoStack, redoStack: [] };
22	    }
23	    case "UNDO": {
24	      if (state.undoStack.length === 0) return state;
25	      const undoStack = state.undoStack.slice(0, -1);
26	      const command = state.undoStack[state.undoStack.length - 1]!;
27	      return { undoStack, redoStack: [...state.redoStack, command] };
28	    }
29	    case "REDO": {
30	      if (state.redoStack.length === 0) return state;
31	      const redoStack = state.redoStack.slice(0, -1);
32	      const command = state.redoStack[state.redoStack.length - 1]!;
33	      return { undoStack: [...state.undoStack, command], redoStack };
34	    }
35	    case "CLEAR":
36	      return { undoStack: [], redoStack: [] };
37	    default:
38	      return state;
39	  }
40	}
41	
42	interface HistoryContextValue {
43	  /** Push a new command (already executed) onto the undo stack */
44	  push: (command: Command) => void;
45	  /** Undo the last command */
46	  undo: () => void;
47	  /** Redo the last undone command */
48	  redo: () => void;
49	  /** Clear all history */
50	  clear: () => void;
51	  canUndo: boolean;
52	  canRedo: boolean;
53	  /** Current undo stack (most recent last) */
54	  undoStack: readonly Command[];
55	  /** Current redo stack (most recent last) */
56	  redoStack: readonly Command[];
57	}
58	
59	const HistoryCtx = createContext<HistoryContextValue | null>(null);
60	
61	export function HistoryProvider({ children }: { children: ReactNode }) {
62	  const [state, dispatch] = useReducer(historyReducer, { undoStack: [], redoStack: [] });
63	
64	  const push = useCallback((command: Command) => {
65	    dispatch({ type: "PUSH", command });
66	  }, []);
67	
68	  const undo = useCallback(() => {
69	    const command = state.undoStack[state.undoStack.length - 1];
70	    if (command) {
71	      command.undo();
72	      dispatch({ type: "UNDO" });
73	    }
74	  }, [state.undoStack]);
75	
76	  const redo = useCallback(() => {
77	    const command = state.redoStack[state.redoStack.length - 1];
78	    if (command) {
79	      command.execute();
80	      dispatch({ type: "REDO" });
81	    }
82	  }, [state.redoStack]);
83	
84	  const clear = useCallback(() => {
85	    dispatch({ type: "CLEAR" });
86	  }, []);
87	
88	  return (
89	    <HistoryCtx.Provider
90	      value={{
91	        push,
92	        undo,
93	        redo,
94	        clear,
95	        canUndo: state.undoStack.length > 0,
96	        canRedo: state.redoStack.length > 0,
97	        undoStack: state.undoStack,
98	        redoStack: state.redoStack,
99	      }}
100	    >
101	      {children}
102	    </HistoryCtx.Provider>
103	  );
104	}
105	
106	export function useHistory() {
107	  const ctx = useContext(HistoryCtx);
108	  if (!ctx) throw new Error("useHistory must be used within HistoryProvider");
109	  return ctx;
110	}
111	
112	/** Returns the history context or null if not inside a HistoryProvider */
113	export function useOptionalHistory() {
114	  return useContext(HistoryCtx);
115	}
